VALUES
  ('social-worker-moex-06630', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理功能的概念中，指出「係針對組織的各項職位選擇適當的員工，指派其擔任組織中待補位置」，此 一功能為何？', '["組織", "領導", "任用", "規劃"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06631', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作管理的活動與功能中，管理者讓員工清楚明白組織目標，並運用自身的影響力及各種激勵方式， 帶領員工達成組織目標稱之為何？', '["任用", "督導", "領導", "行政"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06632', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關需求評估類型中，針對目標人口群的就業生涯態度進行測量，如進行生涯規劃、價值觀等問卷測量， 以了解案主就業生涯的困境，之後針對案主人口群推動相關的生涯發展服務方案，此類測量屬於何種需 求評估？', '["感覺性需求", "規範性需求", "比較性需求", "表達性需求"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06633', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '方案預算是方案規劃中，重要的資源輸入面向，下列敍述何者屬於方案預算法（Program Budgeting）之範疇？', '["某社福機構的年度總預算為1000萬，其中行政主管與機構督導的支出占150萬", "某社福機構去年的預算為1000萬，今年考量到通貨膨脹，預算增至1100萬", "某社福機構今年青年輔導方案需250萬，老人外展方案需150萬，全部方案之總額為400萬", "某社福機構編列預算的前提是從一無所有開始，機構要為其每年所做的財務進行辯護"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06634', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '人群關係學派主張人類的需求如果被滿足，個人將為組織的目標而努力，管理者只要利用良好的人際互 動關係，即可改善生產效能，該論述興起於霍桑效應（Hawthorne effect），而該研究的代表人物是：', '["泰勒（Frederick W. Taylor）", "馬斯洛（Abraham Maslow）", "梅耶（Elton Mayo）", "韋伯（Max Weber）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06635', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '德爾菲技術法（Delphi technique）類似名義團體法（nominal group technique,NGT），但較為複雜和', '["問題確 定後，團體成員被要求對一系列精心設計的問卷，提出可能的解決方法", "每位團體成員獨立自主地 完成問卷", "團體的每位成員收到一份結果的副本", "在看完結果後，成員再次被要求提出其解決方 法，基本上，初次的結果會激發出新的解決方法，或導致最初立場的改變 ⑤將問卷的結果以謄寫和 複製的方式，編寫在一個醒目的位置"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06636', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '考評者因某種特殊事件或工作上表現不理想，而對受評人能力產生低估之偏失，亦即負向的「以偏概全」 方式。此為何種效應？', '["霍桑效應(Hawthorne effect)", "尖角效應(horn effect)", "刻板印象效應(stereotyping)", "盲點效應(blindness effect)"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06637', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '績效考核對組織人力資源之有效管理相當重要，但在執行考核的前後需要一些配套措施，才可能讓考核 產生意義，這些基本的要件不包括何者？', '["機構強調對人不對事的方式進行檢討", "機構已建置升遷與生涯發展等制度", "機構應以獎勵員工事業前程作為自我成長檢討方向", "機構管理者應充分發揮獎優罰劣的功能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06638', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關員工教育訓練的評估方面，著重在了解員工是否將學到的東西應用到工作職務上，此種評估為 Kirkpatrick提出之「四層次評估」中的那一個模式？', '["學習層次", "行為層次", "反應層次", "結果層次"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06639', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '員工的訓練項目若以機構使命及政策介紹、認識環境及重要人員介紹為主，此為何種訓練？', '["自我訓練", "工作外訓練", "工作中訓練", "職前訓練"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
